interface EntityState<T> {
  ids: string[];
  entities: Record<string, T>;
}
function normalize<T extends {id:string}>(items: T[]): EntityState<T> {
  return {
    ids: items.map(i => i.id),
    entities: Object.fromEntries(items.map(i => [i.id, i]))
  };
}

