function firstUnique(s: string): number {
  const freq = new Map<string, number>();
  for (const ch of s) freq.set(ch, (freq.get(ch) ?? 0) + 1);
  for (let i = 0; i < s.length; i++) {
    if (freq.get(s[i]) === 1) return i;
  }
  return -1;
}

interface Comment { id: string; postId: string; text: string; authorId: string; }
function normalizeComments(comments: Comment[]) {
  const byId = new Map<string, Comment>();
  const byPost = new Map<string, Comment[]>();
  for (const c of comments) {
    byId.set(c.id, c);
    if (!byPost.has(c.postId)) byPost.set(c.postId, []);
    byPost.get(c.postId)!.push(c);
  }
  return { byId, byPost };
}

function lengthOfLongestSubstring(s: string): number {
  const lastSeen = new Map<string, number>();
  let maxLen = 0, left = 0;
  for (let right = 0; right < s.length; right++) {
    const ch = s[right];
    if (lastSeen.has(ch) && lastSeen.get(ch)! >= left) {
      left = lastSeen.get(ch)! + 1;
    }
    lastSeen.set(ch, right);
    maxLen = Math.max(maxLen, right - left + 1);
  }
  return maxLen;
}
